using System;
using System.Collections.Generic;
using System.Xml;

public class ConfigParser
{
    public Dictionary<string, string> ParseXml(string filePath)
    {
        XmlDocument xmlDoc = new XmlDocument();
        try
        {
            xmlDoc.Load(filePath);
        }
        catch (XmlException ex)
        {
            Console.WriteLine($"Error parsing XML: {ex.Message}");
            return null;
        }

        var configSettings = new Dictionary<string, string>();

        XmlElement root = xmlDoc.DocumentElement;

        if (root != null && !string.IsNullOrEmpty(root.GetAttribute("dtd")))
        {
            // Load the referenced DTD
            XmlDocument dtdDoc = new XmlDocument();
            try
            {
                dtdDoc.Load(root.GetAttribute("dtd"));
            }
            catch (XmlException ex)
            {
                Console.WriteLine($"Error loading DTD: {ex.Message}");
            }

            XmlElement dtdRoot = dtdDoc.DocumentElement;

            if (dtdRoot != null && !string.IsNullOrEmpty(dtdRoot.GetAttribute("system")))
            {
                // Validate the XML against the loaded DTD
                try
                {
                    xmlDoc.Validate(new ValidationEventHandler((sender, e) =>
                    {
                        Console.WriteLine($"Validation error: {e.Message}");
                    }));
                }
                catch (XmlException ex)
                {
                    Console.WriteLine($"Error validating XML: {ex.Message}");
                }
            }
        }

        foreach (XmlNode node in root.ChildNodes)
        {
            if (node is XmlElement elem)
            {
                configSettings[elem.GetAttribute("name")] = elem.InnerText;
            }
        }

        return configSettings;
    }
}